// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb.inlined;

import static org.assertj.core.api.Assertions.assertThat;

import java.util.Arrays;
import java.util.List;

import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.model.vocabulary.XSD;
import org.eclipse.rdf4j.sail.lmdb.ValueIds;
import org.junit.jupiter.api.Test;

class DatesTest {

	private final ValueFactory vf = SimpleValueFactory.getInstance();

	private final List<Literal> inlineableLiterals = Arrays.asList(
			// DATETIME with timezone, no fractional seconds
			vf.createLiteral("2023-01-15T10:30:00Z", XSD.DATETIME),
			vf.createLiteral("2023-01-15T10:30:00+05:30", XSD.DATETIME),
			vf.createLiteral("2023-01-15T10:30:00-14:00", XSD.DATETIME),
			// DATETIME with timezone and millisecond fraction
			vf.createLiteral("2023-01-15T10:30:00.123Z", XSD.DATETIME),
			vf.createLiteral("2023-01-15T10:30:00.001-08:00", XSD.DATETIME),
			// DATETIME without timezone
			vf.createLiteral("2023-01-15T10:30:00", XSD.DATETIME),
			vf.createLiteral("2023-01-15T10:30:00.500", XSD.DATETIME),
			vf.createLiteral("1970-01-01T00:00:00", XSD.DATETIME),
			vf.createLiteral("8191-12-31T23:59:59", XSD.DATETIME),
			// DATETIMESTAMP (timezone is required by the datatype)
			vf.createLiteral("2023-01-15T10:30:00Z", XSD.DATETIMESTAMP),
			vf.createLiteral("2023-01-15T10:30:00.999+01:00", XSD.DATETIMESTAMP),
			// DATE without timezone
			vf.createLiteral("2023-01-15", XSD.DATE),
			vf.createLiteral("1970-01-01", XSD.DATE),
			vf.createLiteral("8191-12-31", XSD.DATE),
			// DATE with timezone
			vf.createLiteral("2023-01-15Z", XSD.DATE),
			vf.createLiteral("2023-01-15+05:00", XSD.DATE));

	@Test
	void testDateAndDateTimeLiteralsAreInlined() {
		for (Literal literal : inlineableLiterals) {
			long packed = Values.packLiteral(literal);
			assertThat(packed)
					.as("literal should be inlined: %s", literal)
					.isNotZero();
			assertThat(ValueIds.isInlined(packed))
					.as("packed id should carry the inlined marker: %s", literal)
					.isTrue();
			Literal unpacked = Values.unpackLiteral(packed, vf);
			assertThat(unpacked)
					.as("unpacked literal should equal the original: %s", literal)
					.isEqualTo(literal);
		}
	}

	@Test
	void testDateTimeStampUsesDateTimeStampTypeTag() {
		Literal literal = vf.createLiteral("2023-01-15T10:30:00Z", XSD.DATETIMESTAMP);
		long packed = Values.packLiteral(literal);
		assertThat(packed).as("dateTimeStamp literal should be inlined").isNotZero();
		assertThat(ValueIds.getIdType(packed)).isEqualTo(ValueIds.T_DATETIMESTAMP);
	}

	@Test
	void testNonInlineableDateLiteralsFallBackToDictionary() {
		List<Literal> notInlineable = Arrays.asList(
				// negative years are outside the encodable range
				vf.createLiteral("-0500-01-15", XSD.DATE),
				// years beyond 13 bits
				vf.createLiteral("9999-12-31T23:59:59Z", XSD.DATETIME),
				// sub-millisecond precision does not survive the round-trip
				vf.createLiteral("2023-01-15T10:30:00.123456Z", XSD.DATETIME));
		for (Literal literal : notInlineable) {
			long packed = Values.packLiteral(literal);
			if (packed != 0L) {
				assertThat(Values.unpackLiteral(packed, vf))
						.as("if packed, the round-trip must not be lossy: %s", literal)
						.isEqualTo(literal);
			}
		}
	}
}
